+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return typeof value === "object" && value !== null &&
+    !Array.isArray(value) && Object.getPrototypeOf(value) === Object.prototype;
+}
+
+function camelCaseConfigKey(key: string): string {
+  return key.replace(/-([a-zA-Z0-9])/g, (_, char) => char.toUpperCase());
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+  values: Record<string, unknown> = {},
+): Record<string, unknown> {
+  for (const [rawKey, item] of Object.entries(value)) {
+    const key = prefix ? `${prefix}.${camelCaseConfigKey(rawKey)}` : camelCaseConfigKey(rawKey);
+    if (isPlainObject(item)) {
+      flattenConfig(item, key, values);
+    } else {
+      values[key] = item;
+    }
+  }
+  return values;
+}
+
+function parseRcConfig(content: string): Record<string, unknown> {
+  const values: Record<string, unknown> = {};
+  for (const rawLine of content.split(/\\r?\
/)) {
+    const line = rawLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const equals = line.indexOf("=");
+    if (equals === -1) throw new Error(`Invalid RC entry "${rawLine}".`);
+    const key = line.slice(0, equals).trim();
+    let value = line.slice(equals + 1).trim();
+    if (!key) throw new Error("RC entry is missing a key.");
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length === 1) {
+        throw new Error(`Unterminated quoted value for "${key}".`);
+      }
+      value = value.slice(1, -1);
+    }
+    values[camelCaseConfigKey(key)] = value === "true" ? true
+      : value === "false" ? false
+      : value !== "" && /^[-+]?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value) ? Number(value)
+      : value;
+  }
+  return values;
+}
