+
+test("command: loads JSON config with CLI precedence and cached values", async () => {
+  const dir = await configDir({
+    "tool.json": JSON.stringify({ "dry-run": false, count: 0, tags: ["a", "b"], nested: { name: "value" }, ignored: true }),
+  });
+  const cmd = new Command()
+    .throwErrors()
+    .config({ name: "tool", searchPaths: [dir] })
+    .option("--dry-run", "...")
+    .option("--count <count:number>", "...")
+    .option("--tags <tag:string>", "...", { collect: true })
+    .option("--nested.name <name>", "...");
+
+  const result = await cmd.parse(["--count", "2"]);
